import graphqlicon from "@styles/assets/images/Techstack/graphql.svg";
import cubit from "@styles/assets/images/Techstack/cubit.svg";
import dart from "@styles/assets/images/Techstack/dart.svg";

import icon1 from "@images/hirescreens/devPages/icons/chooseIcons/idea_card.svg";
import icon2 from "@images/hirescreens/devPages/icons/chooseIcons/secure.svg";
